mapper.select:
select * from `intervention_record`

     and id = #{id}
     and student_id = #{studentId}
     and course_id = #{courseId}
     and teacher_id = #{teacherId}
     and warning_id = #{warningId}

order by create_time desc, id desc

mapper.update:
update `intervention_record`
student_id = #{studentId}, teacher_id = #{teacherId}, course_id = #{courseId}, warning_id = #{warningId}, intervention_type = #{interventionType}, intervention_content = #{interventionContent}, intervention_result = #{interventionResult}, create_time = #{createTime}, update_time = #{updateTime},
where id = #{id}
